// Motor EWMA: calcula proyección de cierre para cada dimensión
// Fórmula: proyección = ejecutado_mtd + (ritmo_ewma × días_restantes) + pipeline

const historico = $('Query Ejecución Diaria (25 días)').all().map(i => i.json);
const pipeline = $('Query Pipeline OTs Pendientes').all().map(i => i.json);
const budgets = $('Query Budget del Mes').all().map(i => i.json);

const HOY = new Date();
const ANIO = HOY.getFullYear();
const MES = HOY.getMonth() + 1;
const DIA_DEL_MES = HOY.getDate();
const DIAS_EN_MES = new Date(ANIO, MES, 0).getDate();
const DIAS_RESTANTES = DIAS_EN_MES - DIA_DEL_MES;
const ALPHA = 0.3; // parámetro EWMA

// Agrupar histórico por dimensión
const byDimension = {};
for (const row of historico) {
  const key = `${row.zona || 'total'}|${row.contratista_id || 'todos'}|${row.categoria_contable || 'todas'}`;
  if (!byDimension[key]) byDimension[key] = { dias: [], zona: row.zona, contratista_id: row.contratista_id, categoria_contable: row.categoria_contable };
  byDimension[key].dias.push({ dia: row.dia, gasto: parseFloat(row.gasto_dia || 0) });
}

const resultados = [];

// Calcular EWMA por dimensión
for (const [key, dim] of Object.entries(byDimension)) {
  const diasOrdenados = dim.dias.sort((a, b) => new Date(b.dia) - new Date(a.dia)); // más reciente primero

  // Solo últimos 20 días
  const ultimos20 = diasOrdenados.slice(0, 20);

  // Ejecutado MTD (mes actual solamente)
  const ejecutadoMTD = dim.dias
    .filter(d => new Date(d.dia).getMonth() + 1 === MES && new Date(d.dia).getFullYear() === ANIO)
    .reduce((sum, d) => sum + d.gasto, 0);

  // EWMA del ritmo diario
  let ewma = ultimos20[0]?.gasto || 0;
  for (let i = 1; i < ultimos20.length; i++) {
    ewma = ALPHA * ultimos20[i].gasto + (1 - ALPHA) * ewma;
  }

  // Pipeline para esta dimensión
  const pipelineRow = pipeline.find(p =>
    (p.zona === dim.zona || (!p.zona && !dim.zona)) &&
    (p.contratista_id === dim.contratista_id || (!p.contratista_id && !dim.contratista_id)) &&
    (p.categoria_contable === dim.categoria_contable || (!p.categoria_contable && !dim.categoria_contable))
  );
  const costosPipeline = parseFloat(pipelineRow?.costo_pipeline_esperado || 0);

  // Budget para esta dimensión
  const budgetRow = budgets.find(b =>
    (b.zona === dim.zona || (!b.zona && !dim.zona)) &&
    (b.contratista_id === dim.contratista_id || (!b.contratista_id && !dim.contratista_id)) &&
    (b.categoria_contable === dim.categoria_contable || (!b.categoria_contable && !dim.categoria_contable))
  );
  const budgetMes = parseFloat(budgetRow?.budget_mes || 0);

  // Proyección central
  const proyeccionCentral = ejecutadoMTD + (ewma * DIAS_RESTANTES) + costosPipeline;

  // Banda de confianza P20/P80 (±20% del componente de ritmo)
  const componenteRitmo = ewma * DIAS_RESTANTES;
  const proyeccionP20 = ejecutadoMTD + (componenteRitmo * 0.8) + costosPipeline;
  const proyeccionP80 = ejecutadoMTD + (componenteRitmo * 1.2) + costosPipeline;

  // Desviación vs budget
  const desviacionPct = budgetMes > 0
    ? ((proyeccionCentral - budgetMes) / budgetMes) * 100
    : null;

  // Nivel de confianza: más alto cuando tenemos más datos
  const nivelConfianza = Math.min(0.95, 0.5 + (ultimos20.length / 20) * 0.45);

  resultados.push({
    json: {
      anio: ANIO,
      mes: MES,
      fecha_calculo: HOY.toISOString().split('T')[0],
      dia_del_mes: DIA_DEL_MES,
      zona: dim.zona,
      contratista_id: dim.contratista_id,
      categoria_contable: dim.categoria_contable,
      ejecutado_mtd: Math.round(ejecutadoMTD),
      ritmo_ewma: Math.round(ewma),
      pipeline_esperado: Math.round(costosPipeline),
      proyeccion_central: Math.round(proyeccionCentral),
      proyeccion_p20: Math.round(proyeccionP20),
      proyeccion_p80: Math.round(proyeccionP80),
      budget_mes: budgetMes || null,
      desviacion_pct: desviacionPct !== null ? Math.round(desviacionPct * 100) / 100 : null,
      nivel_confianza: Math.round(nivelConfianza * 100) / 100,
      metodo: 'ewma',
      // Para alertas
      generar_alerta_A10: desviacionPct !== null && desviacionPct > 10 && DIAS_RESTANTES >= 5,
      generar_alerta_A8: desviacionPct !== null && desviacionPct > 5 && !( desviacionPct > 10 && DIAS_RESTANTES >= 5 )
    }
  });
}

// Si no hay datos, retornar proyección base en cero
if (resultados.length === 0) {
  resultados.push({
    json: {
      anio: ANIO, mes: MES,
      fecha_calculo: HOY.toISOString().split('T')[0],
      dia_del_mes: DIA_DEL_MES,
      zona: null, contratista_id: null, categoria_contable: null,
      ejecutado_mtd: 0, ritmo_ewma: 0, pipeline_esperado: 0,
      proyeccion_central: 0, proyeccion_p20: 0, proyeccion_p80: 0,
      nivel_confianza: 0, metodo: 'ewma',
      generar_alerta_A10: false, generar_alerta_A8: false
    }
  });
}

return resultados;
